import React from "react";

const Layout = ({ children }) => {
  return (
    <div style={styles.wrapper}>

      {/* SIDEBAR */}
      <div style={styles.sidebar}>
        <h2 style={{ color: "#22c55e" }}>DailyWorker</h2>

        <a href="/customer" style={styles.link}>Customer</a>
        <a href="/labour" style={styles.link}>Labour</a>
        <a href="/login" style={styles.link}>Login</a>
      </div>

      {/* MAIN */}
      <div style={styles.main}>
        {children}
      </div>

    </div>
  );
};

export default Layout;

const styles = {
  wrapper: {
    display: "flex",
    height: "100vh",
    background: "#0b1220",
    color: "#e5e7eb",
    fontFamily: "Segoe UI"
  },

  sidebar: {
    width: "220px",
    background: "#111a2e",
    padding: "20px",
    display: "flex",
    flexDirection: "column",
    gap: "15px"
  },

  main: {
    flex: 1,
    padding: "20px"
  },

  link: {
    color: "#94a3b8",
    textDecoration: "none"
  }
};
